using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class SystemThresholdConfiguration : IEntityTypeConfiguration<SystemThreshold>{public void Configure(EntityTypeBuilder<SystemThreshold> builder){builder.ToTable("system_thresholds");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("threshold_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Code).HasMaxLength(60).IsRequired();builder.Property(e => e.Name).HasMaxLength(100).IsRequired();builder.Property(e => e.Category).HasMaxLength(30).IsRequired();builder.Property(e => e.NumericValue).HasColumnType("decimal(12,4)");builder.Property(e => e.Unit).HasMaxLength(30);builder.HasOne(e => e.UpdatedByUser).WithMany().HasForeignKey(e => e.UpdatedByUserId);builder.HasIndex(e => e.Code).IsUnique();builder.HasIndex(e => e.Category);}}
